GUISumRechargeReward = class("GUISumRechargeReward", IGUIWindow)

function GUISumRechargeReward:onLoad()
    local name = string.gsub(self.__name, ".json", "-")
    self.ivIconBg = self:getChildWindowByName(name .. "Icon-Bg", GUIType.StaticImage)
    self.ivIcon = self:getChildWindowByName(name .. "Icon", GUIType.StaticImage)
    self.ivEffect = self:getChildWindowByName(name .. "Effect", GUIType.StaticImage)
    self.tvCount = self:getChildWindowByName(name .. "Count", GUIType.StaticText)
    self.tvName = self:getChildWindowByName(name .. "Name", GUIType.StaticText)
    self.reward = {}

    self.ivIcon:registerEvent(GUIEvent.Click, function()
        self:onClickIcon()
    end)
end

function GUISumRechargeReward:setRewardItem(reward)
    local backLength = string.len(reward.Background)
    if backLength > 2 then
        self.ivIconBg:SetImage(reward.Background)
    end
    local iconLength = string.len(reward.Icon)
    if iconLength > 2 then
        self.ivIcon:SetImage(reward.Icon)
    else
        GuiItemStack.showItemIcon(self.ivIcon, reward.RewardId, reward.Meta, "")
    end
    self.reward = reward
    self.ivEffect:SetEffectName(reward.Effect)
    self.tvCount:SetText(string.format("x%s", tostring(reward.Count)))
    self.tvName:SetText(Lang:getString(reward.NameLang))
    local count = self.root:GetChildCount()
    for pos = 1, count do
        local child = self.root:GetChildByIndex(pos - 1)
        local xPos = child:GetXPosition()
        xPos[1] = xPos[1] + reward.OffsetX
        child:SetXPosition(xPos)
        local yPos = child:GetYPosition()
        yPos[1] = yPos[1] + reward.OffsetY
        child:SetYPosition(yPos)
    end
end

function GUISumRechargeReward:onClickIcon()
    SumRechargeShowItemDetailEvent:invoke(self.reward)
end